// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {EIP712} from "@openzeppelin/contracts/utils/cryptography/EIP712.sol";
import {ECDSA} from "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

/**
 * BreachRegistry — Registro inmutable de filtraciones de datos.
 *
 * Modelo híbrido de registro:
 *
 *   1. El "verifier" oficial (servidor backend de ChainWatch) firma off-chain
 *      una EIP-712 "BreachEvidence" garantizando que verificó la filtración.
 *   2. Cualquiera (server o user) puede enviar la transacción on-chain
 *      llamando a recordBreachWithProof(...) con esa firma.
 *   3. El reporter on-chain queda como msg.sender (quien pagó gas).
 *      El beneficiary queda como el address designado en el payload
 *      (típicamente el usuario afectado).
 *
 * Esto permite dos flujos:
 *   - Server-paid: el backend firma Y envía la tx. Gasless para el user.
 *   - User-paid:   el backend firma, el frontend del user envía la tx
 *                  con beneficiary = msg.sender. El user "reclama"
 *                  la evidencia como propia.
 *
 * Anti-replay:
 *   - El contrato lleva un nonce auto-incremental por verifier.
 *   - Cada firma tiene un deadline (timestamp Unix) tras el cual no se acepta.
 *
 * Anti-duplicados:
 *   - Mapping (targetHash, sourceHash) => bool evita registrar la misma
 *     brecha desde la misma fuente más de una vez.
 *   - Diferentes fuentes (HIBP vs manual) sí pueden coexistir.
 */
contract BreachRegistry is EIP712, Ownable {
    using ECDSA for bytes32;

    bytes32 private constant _BREACH_EVIDENCE_TYPEHASH = keccak256(
        "BreachEvidence(bytes32 targetHash,string source,string dataType,address beneficiary,uint256 nonce,uint256 deadline)"
    );

    // ----------------------------------------------------------------------
    // Estado
    // ----------------------------------------------------------------------

    struct BreachRecord {
        bytes32 targetHash;
        string  source;
        string  dataType;
        address beneficiary;
        address reporter;
        uint256 timestamp;
    }

    BreachRecord[] public records;

    // verifier autorizado para firmar evidencias EIP-712 (la wallet del server)
    mapping(address => bool) public isVerifier;

    // nonce actual por verifier — cada firma exitosa lo incrementa
    mapping(address => uint256) public nonces;

    // (targetHash, sourceHash) => recordId+1 (0 = no registrado)
    mapping(bytes32 => mapping(bytes32 => uint256)) private _seenSource;

    // beneficiary => lista de ids de records donde es el beneficiario
    mapping(address => uint256[]) private _beneficiaryRecords;

    // ----------------------------------------------------------------------
    // Eventos
    // ----------------------------------------------------------------------

    event BreachRecorded(
        uint256 indexed id,
        bytes32 indexed targetHash,
        address indexed beneficiary,
        string  source,
        string  dataType,
        address reporter,
        uint256 nonce
    );

    event VerifierSet(address indexed verifier, bool enabled);

    // ----------------------------------------------------------------------
    // Errores (gas-efficient revert reasons)
    // ----------------------------------------------------------------------

    error NotAVerifier(address signer);
    error SignatureExpired(uint256 deadline);
    error InvalidNonce(uint256 expected, uint256 provided);
    error DuplicateBreach(bytes32 targetHash, bytes32 sourceHash);

    // ----------------------------------------------------------------------
    // Constructor
    // ----------------------------------------------------------------------

    constructor(address initialVerifier)
        EIP712("ChainWatch.BreachRegistry", "1")
        Ownable(msg.sender)
    {
        if (initialVerifier != address(0)) {
            isVerifier[initialVerifier] = true;
            emit VerifierSet(initialVerifier, true);
        }
    }

    // ----------------------------------------------------------------------
    // Admin (owner-only)
    // ----------------------------------------------------------------------

    function setVerifier(address verifier, bool enabled) external onlyOwner {
        isVerifier[verifier] = enabled;
        emit VerifierSet(verifier, enabled);
    }

    // ----------------------------------------------------------------------
    // Función principal
    // ----------------------------------------------------------------------

    /**
     * Registra una brecha verificando una firma EIP-712 del verifier.
     *
     * @param targetHash   keccak256 del dato afectado (email/wallet/teléfono)
     * @param source       fuente que confirmó la brecha ("hibp", "manual", etc)
     * @param dataType     "email" | "phone" | "wallet"
     * @param beneficiary  a quién pertenece la evidencia (típicamente el user)
     * @param nonce        nonce actual del verifier (consultar nonces[verifier])
     * @param deadline     timestamp tras el cual la firma deja de ser válida
     * @param signature    firma EIP-712 producida por un verifier autorizado
     * @return recordId    id del registro creado
     */
    function recordBreachWithProof(
        bytes32 targetHash,
        string calldata source,
        string calldata dataType,
        address beneficiary,
        uint256 nonce,
        uint256 deadline,
        bytes calldata signature
    ) external returns (uint256 recordId) {
        if (block.timestamp > deadline) revert SignatureExpired(deadline);

        bytes32 structHash = keccak256(
            abi.encode(
                _BREACH_EVIDENCE_TYPEHASH,
                targetHash,
                keccak256(bytes(source)),
                keccak256(bytes(dataType)),
                beneficiary,
                nonce,
                deadline
            )
        );

        bytes32 digest = _hashTypedDataV4(structHash);
        address signer = digest.recover(signature);

        if (!isVerifier[signer]) revert NotAVerifier(signer);
        if (nonces[signer] != nonce) revert InvalidNonce(nonces[signer], nonce);

        bytes32 sourceHash = keccak256(bytes(source));
        if (_seenSource[targetHash][sourceHash] != 0) {
            revert DuplicateBreach(targetHash, sourceHash);
        }

        unchecked {
            nonces[signer] = nonce + 1;
        }

        records.push(
            BreachRecord({
                targetHash:  targetHash,
                source:      source,
                dataType:    dataType,
                beneficiary: beneficiary,
                reporter:    msg.sender,
                timestamp:   block.timestamp
            })
        );

        recordId = records.length - 1;
        _seenSource[targetHash][sourceHash] = recordId + 1;
        _beneficiaryRecords[beneficiary].push(recordId);

        emit BreachRecorded(
            recordId,
            targetHash,
            beneficiary,
            source,
            dataType,
            msg.sender,
            nonce
        );
    }

    // ----------------------------------------------------------------------
    // Lecturas auxiliares
    // ----------------------------------------------------------------------

    function totalBreaches() external view returns (uint256) {
        return records.length;
    }

    /**
     * Devuelve los ids de records donde el address es beneficiario.
     * Útil para que el frontend muestre "tus brechas registradas".
     */
    function recordsOfBeneficiary(address beneficiary)
        external
        view
        returns (uint256[] memory)
    {
        return _beneficiaryRecords[beneficiary];
    }

    function isRegistered(bytes32 targetHash, string calldata source)
        external
        view
        returns (bool)
    {
        return _seenSource[targetHash][keccak256(bytes(source))] != 0;
    }

    /**
     * Expone el domain separator EIP-712 para que el frontend pueda
     * verificar/firmar fuera del flujo normal si lo necesita.
     */
    function domainSeparator() external view returns (bytes32) {
        return _domainSeparatorV4();
    }
}

